using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

public partial class DocumentSummarizer : IDocumentSummarizer
{
    // Common English stop words excluded from scoring
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","of","in","to","for",
        "with","on","at","from","by","about","as","into","through","during",
        "before","after","above","below","between","out","off","over","under",
        "again","further","then","once","here","there","when","where","why",
        "how","all","both","each","few","more","most","other","some","such",
        "no","nor","not","only","own","same","so","than","too","very","it",
        "its","this","that","these","those","i","me","my","we","our","you",
        "your","he","him","his","she","her","they","them","their","what",
        "which","who","whom"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        // Build word frequency map (excluding stop words)
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
            }
        }

        // Score each sentence by the sum of its word frequencies
        var scored = sentences
            .Select((sentence, index) => new
            {
                Sentence = sentence,
                Index = index,
                Score = Tokenize(sentence)
                    .Where(w => wordFrequency.ContainsKey(w))
                    .Sum(w => wordFrequency[w])
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static IEnumerable<string> Tokenize(string sentence)
    {
        return WordRegex().Matches(sentence).Select(m => m.Value.ToLowerInvariant());
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        var originalWordCount = request.DocumentText.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
        var summaryWordCount = summary.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWordCount,
            SummaryWordCount = summaryWordCount
        });
    }
}

